dev-browser --headless --browser axi-bench-dev-browser-github_issue_investigation-run1 << 'EOF'
const page = await browser.getPage("main");

const result = await page.evaluate(() => {
  // Look for the open issues count more broadly
  let openCount = null;

  // Check for elements containing "Open" near a number
  const spans = document.querySelectorAll('span, a, button');
  for (const el of spans) {
    const text = el.textContent.trim();
    if (/^\d[\d,]* Open$/.test(text) || /^Open \d[\d,]*$/.test(text)) {
      openCount = text;
      break;
    }
  }

  // Try the issues tab counter
  if (!openCount) {
    const tabItems = document.querySelectorAll('[role="tab"], .tabnav-tab, #issues-tab');
    for (const tab of tabItems) {
      if (tab.textContent.includes('Issues')) {
        const counter = tab.querySelector('.Counter, [data-testid="count"]');
        if (counter) {
          openCount = counter.textContent.trim() + ' open issues';
          break;
        }
      }
    }
  }

  // Look for the "X Open" text in the issues list header
  if (!openCount) {
    const headers = document.querySelectorAll('h2, h3, [class*="Header"], [class*="header"]');
    for (const h of headers) {
      if (/\d+\s+Open/.test(h.textContent)) {
        openCount = h.textContent.trim().substring(0, 100);
        break;
      }
    }
  }

  // Search all text nodes
  if (!openCount) {
    const walker = document.createTreeWalker(document.body, NodeFilter.SHOW_TEXT);
    let node;
    while (node = walker.nextNode()) {
      if (/\d[\d,]*\s+[Oo]pen/.test(node.textContent)) {
        openCount = node.textContent.trim().substring(0, 100);
        break;
      }
    }
  }

  return { openCount, pageTitle: document.title };
});

console.log(JSON.stringify(result, null, 2));
EOF

