const page = await browser.newPage();
await page.goto('https://en.wikipedia.org/wiki/List_of_Nobel_laureates_in_Physics');
await page.waitForSelector('table.wikitable');

const result = await page.evaluate(() => {
  const tables = document.querySelectorAll('table.wikitable');
  const yearData = {};

  for (const table of tables) {
    const trs = table.querySelectorAll('tr');
    let currentYear = null;

    for (const tr of trs) {
      const tds = tr.querySelectorAll('td');
      if (tds.length === 0) continue;

      const firstCell = tds[0].innerText.trim();

      // If first cell is a year >= 2023
      if (/^20(2[3-9]|[3-9]\d)$/.test(firstCell)) {
        currentYear = firstCell;
        if (!yearData[currentYear]) yearData[currentYear] = [];
        // Get all laureates in this row
        const cells = Array.from(tds).map(td => td.innerText.trim());
        yearData[currentYear].push(cells);
      } else if (currentYear && tds.length >= 2) {
        // Continuation row for same year (additional laureates)
        const cells = Array.from(tds).map(td => td.innerText.trim());
        // Check if it looks like a laureate row (no year in first cell)
        if (!/^\d{4}$/.test(firstCell)) {
          yearData[currentYear].push(cells);
        }
      }
    }
  }

  return yearData;
});

